MsgPack::bin_t<uint8_t> get_emg_frame() {
    // --- Kritischer Abschnitt START ---
    // Nur die Zeiger und Flags, die von einem Interrupt geändert werden könnten,
    // müssen atomar gelesen werden.
    noInterrupts();
    uint16_t tail = last_sent;
    uint16_t h = head;
    bool ovf = overflowed;
    overflowed = false; // Flag hier zurücksetzen
    interrupts();
    // --- Kritischer Abschnitt ENDE ---

    MsgPack::bin_t<uint8_t> out;
    uint16_t count = (h >= tail) ? (h - tail) : (RING_SIZE - tail + h);

    if (count == 0) return out; // Keine neuen Daten

    static uint8_t frame[1 + 4 + RING_SIZE * (1 + sizeof(float) * NUM_SENSORS) + 2];
    size_t idx = 0;
    uint16_t crc = 0;

    uint8_t frame_count = (count > 255) ? 255 : count;
    frame[idx++] = frame_count;

    // Ersten Zeitstempel lesen (ist sicher, da `head` nicht über `tail` hinausläuft)
    uint32_t t0 = ringBuf[tail].t_ms;
    memcpy(&frame[idx], &t0, sizeof(t0));
    idx += sizeof(t0);

    uint32_t prev_t = t0;
    uint16_t current_read_idx = tail;
    for (uint16_t i = 0; i < frame_count; i++) {
        // Lokale, NICHT-volatile Kopie erstellen. Dies ist die entscheidende Korrektur.
        Sample local_sample = ringBuf[current_read_idx];

        uint32_t dt = local_sample.t_ms - prev_t;
        frame[idx++] = (dt > 255) ? 255 : (uint8_t)dt;
        prev_t = local_sample.t_ms;

        // Jetzt mit der sicheren, lokalen Kopie arbeiten - das funktioniert.
        memcpy(&frame[idx], local_sample.values, sizeof(float) * NUM_SENSORS);
        idx += sizeof(float) * NUM_SENSORS;

        current_read_idx = (current_read_idx + 1) % RING_SIZE;
    }

    // CRC16 berechnen
    for (size_t i = 0; i < idx; i++) {
        crc = crc16_update(crc, frame[i]);
    }
    memcpy(&frame[idx], &crc, sizeof(crc));
    idx += sizeof(crc);

    // Lesezeiger (last_sent) atomar aktualisieren
    noInterrupts();
    last_sent = current_read_idx;
    interrupts();

    if (ovf) {
        out.push_back(0x21); // '!'
    }

    // Frame in den MsgPack-Container kopieren
    // out.assign() ist oft effizienter als eine Schleife mit push_back
    out.assign(frame, frame + idx); 

    return out;
}
```

### Kritische Reflexion: Die Semantik von `volatile`

Dieser Fehler ist ein perfektes Lehrbeispiel für die korrekte Anwendung von `volatile`.
Eine wissenschaftlich fundierte "Faustregel" lautet:
> `volatile` wird ausschließlich für Objekte verwendet, deren Wert sich durch Mechanismen ändern kann, die dem Compiler unbekannt sind. Die typischen Fälle sind:
> 1.  **Memory-Mapped Hardware-Register:** Ein Statusregister einer Peripherieeinheit (z.B. UART).
> 2.  **Variablen, die in einer Interrupt-Service-Routine (ISR) modifiziert werden** und außerhalb der ISR gelesen werden (genau dein Anwendungsfall für `ringBuf`, `head`, etc.).
> 3.  **Variablen, die von einem anderen Thread in einem Multithreading-System modifiziert werden** (obwohl hier moderne atomare Operationen oft die bessere Wahl sind).

Eine Variable, die nur innerhalb einer einzigen Funktion existiert und auf die von außen nicht zugegriffen werden kann, ist **niemals** `volatile`.

Du bist auf dem richtigen Weg! Solche Compilerfehler sind keine Hindernisse, sondern wertvolle Lektionen, die das Verständnis für die zugrundeliegenden Systemprinzipien schärfen.

