// 1. Eine leere, lokale (nicht-volatile) Struktur auf dem Stack anlegen.
Sample local_sample; 

// 2. Den Speicherinhalt explizit kopieren.
//    Wir casten den volatile Zeiger zu einem const void*, den memcpy erwartet.
memcpy(&local_sample, 
       (const void*)&ringBuf[current_read_idx], 
       sizeof(Sample));

// Ab hier ist alles wie gehabt, denn local_sample ist nun eine sichere, 
// nicht-volatile Kopie und kann problemlos verwendet werden.
uint32_t dt = local_sample.t_ms - prev_t;
// ... usw.
```

